WHERE g.deleted=0

    AND (sp.student_no LIKE CONCAT('%', #{query.keyword}, '%') OR sp.chinese_name LIKE CONCAT('%', #{query.keyword}, '%') OR sp.english_name LIKE CONCAT('%', #{query.keyword}, '%') OR c.course_name LIKE CONCAT('%', #{query.keyword}, '%'))

AND g.offering_id=#{query.offeringId}
AND o.teacher_id=#{query.teacherId}
AND g.grade_status=#{query.gradeStatus}
